using namespace std;

unordered_map<long long, int> depth_cache;

int compute_depth(long long x) {
    if (x == 1) return 0;
    if (depth_cache.find(x) != depth_cache.end()) {
        return depth_cache[x];
    }
    int cnt = 0;
    long long n = x;
    while (n) {
        cnt += n & 1;
        n >>= 1;
    }
    int depth = 1 + compute_depth(cnt);
    depth_cache[x] = depth;
    return depth;
}

vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    vector<long long> answer;
    vector<int> depths(nums.size());
    for (int i = 0; i < nums.size(); ++i) {
        depths[i] = compute_depth(nums[i]);
    }

    for (const auto& query : queries) {
        if (query[0] == 1) {
            long long l = query[1];
            long long r = query[2];
            long long k = query[3];
            int count = 0;
            for (int i = l; i <= r; ++i) {
                if (depths[i] == k) {
                    count++;
                }
            }
            answer.push_back(count);
        } else if (query[0] == 2) {
            long long idx = query[1];
            long long val = query[2];
            nums[idx] = val;
            depths[idx] = compute_depth(val);
        }
    }
    return answer;
}

