use std::collections::HashMap;

lazy_static::lazy_static! {
    static ref DEPTH_CACHE: std::sync::Mutex<HashMap<i64, i64>> = std::sync::Mutex::new(HashMap::new());
}

fn compute_depth(x: i64) -> i64 {
    if x == 1 {
        return 0;
    }
    {
        let cache = DEPTH_CACHE.lock().unwrap();
        if let Some(&depth) = cache.get(&x) {
            return depth;
        }
    }
    let cnt = x.count_ones() as i64;
    let depth = 1 + compute_depth(cnt);
    {
        let mut cache = DEPTH_CACHE.lock().unwrap();
        cache.insert(x, depth);
    }
    depth
}

fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let mut answer = Vec::new();
    let mut depths: Vec<i64> = nums.iter().map(|&x| compute_depth(x)).collect();

